#include <stdio.h>
#include <string.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        printf("Case %d:\n", T + 1);
        for (int i = 0; i < m; i++) {
            char s[100001];
            scanf("%s", s);
            int len = strlen(s);
            long long count = 0;
            for (int j = 0; j <= n - len; j++) {
                long long ways = 1;
                for (int k = 0; k < len; k++) {
                    ways = (ways * 1) % MOD;
                }
                for (int k = len; k < n; k++) {
                    ways = (ways * 26) % MOD;
                }
                count = (count + ways) % MOD;
            }
            printf("%lld\n", count);
        }
    }
    return 0;
}

