import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            System.out.println("Case " + (T + 1) + ":");
            for (int i = 0; i < m; i++) {
                String s = sc.next();
                int len = s.length();
                long count = 0;
                for (int j = 0; j <= n - len; j++) {
                    long ways = 1;
                    for (int k = 0; k < len; k++) {
                        ways = (ways * 1) % 1000000007;
                    }
                    for (int k = len; k < n; k++) {
                        ways = (ways * 26) % 1000000007;
                    }
                    count = (count + ways) % 1000000007;
                }
                System.out.println(count);
            }
        }
    }
}

